div.script:
// 
(async function() {
  const gameUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/BPLPremium.html";
  const baseUrl = "https://cdn.jsdelivr.net/gh/rainS-IM/BPLGames@main/";
  const root = document.getElementById('bpl-root');
  const status = document.getElementById('status');

  try {
    // 1. Fetch the code
    const response = await fetch(gameUrl);
    if (!response.ok) throw new Error("Network blocked fetch.");
    const html = await response.text();

    // 2. Prepare the content with the Base tag
    // This ensures all your other jsdelivr links work
    const fullContent = `<base href="${baseUrl}">${html}`;

    // 3. Create the iframe
    const iframe = document.createElement('iframe');
    iframe.style = "position:fixed; top:0; left:0; width:100%; height:100%; border:none; background:#fff;";

    // 4. Use srcdoc (better for Safari than document.write)
    iframe.srcdoc = fullContent;

    // 5. Clear and inject
    root.innerHTML = "";
    root.appendChild(iframe);

  } catch (err) {
    status.innerHTML = `<div style="color:#ff4444;">Status: ${err.message}<br/><small>Safari might be blocking the request.</small></div>`;
    console.error(err);
  }
})();
//
